<?php
$pageTitle='View Job Card';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('job_cards');
$pdo=getDB();
$id=(int)($_GET['id']??0);
$stmt=$pdo->prepare('SELECT jc.*,cc.cost_center_code,cc.cost_center_name,c.customer_code,u.email technician_email,i.invoice_number FROM '.table('job_cards').' jc LEFT JOIN '.table('cost_centers').' cc ON cc.id=jc.cost_center_id LEFT JOIN '.table('customers').' c ON c.id=jc.customer_id LEFT JOIN '.table('users').' u ON u.id=jc.technician_user_id LEFT JOIN '.table('invoices').' i ON i.id=jc.invoice_id WHERE jc.id=? LIMIT 1');
$stmt->execute([$id]);$job=$stmt->fetch();
if(!$job){flash('error','Job card not found.');redirect(ADMIN_URL.'/erp/job-cards.php');}
enforceScopeAllowed($pdo,(int)($job['company_id']??0),(int)($job['branch_id']??0),(int)($job['warehouse_id']??0),false);
if($_SERVER['REQUEST_METHOD']==='POST'){
  $action=trim((string)($_POST['action']??''));
  $pdo->beginTransaction();
  try{
    $lock=$pdo->prepare('SELECT * FROM '.table('job_cards').' WHERE id=? LIMIT 1 FOR UPDATE');$lock->execute([$id]);$current=$lock->fetch();
    if(!$current){throw new RuntimeException('Job card not found during update.');}
    enforceScopeAllowed($pdo,(int)($current['company_id']??0),(int)($current['branch_id']??0),(int)($current['warehouse_id']??0),true);
    if($action==='add_labor'){
      $hours=max(0,(float)($_POST['hours']??0));$rate=max(0,(float)($_POST['hourly_rate']??setting('default_labor_hourly_rate','150')));
      if($hours<=0){throw new RuntimeException('Labor hours must be greater than zero.');}
      $pdo->prepare('INSERT INTO '.table('job_card_labor').' (job_card_id,technician_user_id,task_name,description,estimated_hours,actual_hours,hourly_rate,line_total,status) VALUES (?,?,?,?,?,?,?,?,?)')->execute([$id,(int)($_POST['technician_user_id']??0)?:null,trim((string)($_POST['task_name']??'Labor')),trim((string)($_POST['description']??'')),$hours,$hours,$rate,round($hours*$rate,2),'completed']);
      jobCardRecalculate($pdo,$id);flash('success','Labor line added.');
    }elseif($action==='add_part'){
      $qty=max(0,(float)($_POST['quantity']??0));$price=max(0,(float)($_POST['unit_price']??0));$productId=(int)($_POST['product_id']??0)?:null;$desc=trim((string)($_POST['description']??'Part'));
      $cost=0.0;if($productId){$p=$pdo->prepare('SELECT name,average_cost,cost_price,price FROM '.table('products').' WHERE id=? LIMIT 1');$p->execute([$productId]);$prod=$p->fetch();if($prod){$desc=$desc==='Part'?$prod['name']:$desc;$cost=(float)($prod['average_cost']?:$prod['cost_price']);if($price<=0){$price=(float)$prod['price'];}}}
      if($qty<=0){throw new RuntimeException('Part quantity must be greater than zero.');}
      $pdo->prepare('INSERT INTO '.table('job_card_parts').' (job_card_id,product_id,description,quantity_planned,quantity_used,unit_price,unit_cost,line_total,status) VALUES (?,?,?,?,?,?,?,?,?)')->execute([$id,$productId,$desc,$qty,$qty,$price,$cost,round($qty*$price,2),'planned']);
      jobCardRecalculate($pdo,$id);flash('success','Part line added.');
    }elseif($action==='start'){
      $pdo->prepare('UPDATE '.table('job_cards').' SET status="in_progress",started_at=COALESCE(started_at,NOW()) WHERE id=? AND status IN ("draft","diagnosis","waiting_parts")')->execute([$id]);flash('success','Job card started.');
    }elseif($action==='complete'){
      issueJobCardParts($pdo,$id);jobCardRecalculate($pdo,$id);$pdo->prepare('UPDATE '.table('job_cards').' SET status="completed",completed_at=NOW() WHERE id=? AND status IN ("draft","diagnosis","in_progress","waiting_parts")')->execute([$id]);flash('success','Job card completed and parts issued.');
    }elseif($action==='invoice'){
      $invoiceId=createInvoiceFromJobCard($pdo,$id);$pdo->commit();flash('success','Invoice created from job card.');redirect(ADMIN_URL.'/erp/view-invoice.php?id='.$invoiceId);
    }elseif($action==='cancel'){
      $pdo->prepare('UPDATE '.table('job_cards').' SET status="cancelled" WHERE id=? AND status NOT IN ("invoiced","cancelled")')->execute([$id]);flash('success','Job card cancelled.');
    }
    logActivity($pdo,'Service','job_card_'.$action,'Job card '.$current['job_card_number'].' action: '.$action.'.','job_card',$id);
    if($pdo->inTransaction()){$pdo->commit();}
  }catch(Throwable $e){if($pdo->inTransaction()){$pdo->rollBack();}flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/view-job-card.php?id='.$id);
}
jobCardRecalculate($pdo,$id);
$stmt->execute([$id]);$job=$stmt->fetch();
$labor=$pdo->prepare('SELECT jcl.*,u.email technician_email FROM '.table('job_card_labor').' jcl LEFT JOIN '.table('users').' u ON u.id=jcl.technician_user_id WHERE jcl.job_card_id=? ORDER BY jcl.id ASC');$labor->execute([$id]);$laborRows=$labor->fetchAll();
$parts=$pdo->prepare('SELECT jcp.*,p.sku,p.name product_name FROM '.table('job_card_parts').' jcp LEFT JOIN '.table('products').' p ON p.id=jcp.product_id WHERE jcp.job_card_id=? ORDER BY jcp.id ASC');$parts->execute([$id]);$partRows=$parts->fetchAll();
$users=$pdo->query('SELECT id,email,first_name,last_name FROM '.table('users').' WHERE status="active" AND (can_login_erp=1 OR role="admin") ORDER BY first_name,email ASC LIMIT 300')->fetchAll();
$products=$pdo->query('SELECT id,sku,name,price,average_cost,cost_price FROM '.table('products').' WHERE active=1 ORDER BY name ASC LIMIT 400')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-start gap-3 mb-4"><div><div class="erp-kicker">Job Card</div><h2 class="h4 mb-1"><?php echo esc($job['job_card_number']); ?></h2><p class="text-secondary mb-0"><?php echo esc(($job['customer_code']? $job['customer_code'].' · ' : '').$job['customer_name'].' · '.trim(($job['vehicle_make']?:'').' '.($job['vehicle_model']?:'').' '.($job['plate_number']?:''))); ?></p></div><div class="d-flex flex-wrap gap-2"><span class="badge fs-6 bg-<?php echo esc(statusTone($job['status'])); ?>"><?php echo esc(str_replace('_',' ',ucwords($job['status'],'_'))); ?></span><a class="btn btn-outline-dark" href="<?php echo esc(ADMIN_URL); ?>/erp/document-attachments.php?type=job_card&id=<?php echo (int)$job['id']; ?>">Attachments</a><a class="btn btn-outline-secondary" href="<?php echo esc(ADMIN_URL); ?>/erp/job-cards.php">Back</a></div></div>
<div class="row g-4 mb-4"><div class="col-md-3"><div class="card-admin p-4"><div class="erp-kicker">Labor</div><div class="metric-sm"><?php echo money($job['labor_total']); ?></div></div></div><div class="col-md-3"><div class="card-admin p-4"><div class="erp-kicker">Parts</div><div class="metric-sm"><?php echo money($job['parts_total']); ?></div></div></div><div class="col-md-3"><div class="card-admin p-4"><div class="erp-kicker">Total</div><div class="metric-sm"><?php echo money($job['estimated_total']); ?></div></div></div><div class="col-md-3"><div class="card-admin p-4"><div class="erp-kicker">Actual Cost</div><div class="metric-sm"><?php echo money($job['actual_cost']); ?></div></div></div></div>
<div class="row g-4"><div class="col-xl-8"><div class="card-admin p-4 mb-4"><div class="row g-3"><div class="col-md-6"><strong>Technician:</strong> <?php echo esc($job['technician_email']?:'Unassigned'); ?></div><div class="col-md-6"><strong>Cost Center:</strong> <?php echo esc(trim(($job['cost_center_code']?:'').' '.($job['cost_center_name']?:''))?:'—'); ?></div><div class="col-12"><strong>Complaint</strong><div class="text-secondary"><?php echo nl2br(esc($job['complaint']?:'—')); ?></div></div><div class="col-md-6"><strong>Diagnosis</strong><div class="text-secondary"><?php echo nl2br(esc($job['diagnosis']?:'—')); ?></div></div><div class="col-md-6"><strong>Recommendation</strong><div class="text-secondary"><?php echo nl2br(esc($job['recommendation']?:'—')); ?></div></div></div></div><div class="table-wrap table-responsive mb-4"><div class="table-toolbar"><div><div class="erp-kicker">Labor</div><h2 class="h5 mb-0">Tasks & Technician Hours</h2></div></div><table class="table"><thead><tr><th>Task</th><th>Technician</th><th>Hours</th><th>Rate</th><th>Total</th></tr></thead><tbody><?php foreach($laborRows as $row): ?><tr><td><strong><?php echo esc($row['task_name']); ?></strong><div class="small text-secondary"><?php echo esc($row['description']); ?></div></td><td><?php echo esc($row['technician_email']?:'—'); ?></td><td><?php echo number_format((float)$row['actual_hours'],2); ?></td><td><?php echo money($row['hourly_rate']); ?></td><td><?php echo money($row['line_total']); ?></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><div class="table-toolbar"><div><div class="erp-kicker">Parts</div><h2 class="h5 mb-0">Parts Planned / Used</h2></div></div><table class="table"><thead><tr><th>Part</th><th>Qty</th><th>Price</th><th>Cost</th><th>Total</th><th>Status</th></tr></thead><tbody><?php foreach($partRows as $row): ?><tr><td><strong><?php echo esc(($row['sku']?:'').' · '.($row['description']?:$row['product_name'])); ?></strong></td><td><?php echo number_format((float)$row['quantity_used'],2); ?></td><td><?php echo money($row['unit_price']); ?></td><td><?php echo money($row['unit_cost']); ?></td><td><?php echo money($row['line_total']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($row['status'])); ?>"><?php echo esc($row['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div><div class="col-xl-4"><div class="card-admin p-4 mb-4"><div class="erp-kicker">Workflow</div><div class="d-grid gap-2 mt-3"><?php if(in_array($job['status'],['draft','diagnosis','waiting_parts'],true)): ?><form method="post"><button class="btn btn-warning w-100" name="action" value="start">Start Job</button></form><?php endif; ?><?php if(in_array($job['status'],['draft','diagnosis','in_progress','waiting_parts'],true)): ?><form method="post"><button class="btn btn-success w-100" name="action" value="complete">Complete & Issue Parts</button></form><?php endif; ?><?php if($job['status']==='completed'): ?><form method="post"><button class="btn btn-brand w-100" name="action" value="invoice">Create Invoice</button></form><?php endif; ?><?php if(!in_array($job['status'],['invoiced','cancelled'],true)): ?><form method="post"><button class="btn btn-outline-danger w-100" name="action" value="cancel">Cancel</button></form><?php endif; ?></div></div><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="add_labor"><div class="erp-kicker">Add Labor</div><input class="form-control mb-2" name="task_name" placeholder="Task name"><textarea class="form-control mb-2" name="description" rows="2" placeholder="Description"></textarea><select class="form-select mb-2" name="technician_user_id"><option value="0">Technician</option><?php foreach($users as $u): ?><option value="<?php echo (int)$u['id']; ?>"><?php echo esc($u['email']); ?></option><?php endforeach; ?></select><div class="row g-2"><div class="col-6"><input class="form-control" type="number" step="0.01" name="hours" placeholder="Hours"></div><div class="col-6"><input class="form-control" type="number" step="0.01" name="hourly_rate" value="<?php echo esc(setting('default_labor_hourly_rate','150')); ?>"></div></div><button class="btn btn-outline-primary w-100 mt-2">Add Labor</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="add_part"><div class="erp-kicker">Add Part</div><select class="form-select mb-2" name="product_id"><option value="0">Custom part</option><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc(($p['sku']?:'').' · '.$p['name'].' · '.money($p['price'])); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="description" placeholder="Description"><div class="row g-2"><div class="col-4"><input class="form-control" type="number" step="0.01" name="quantity" placeholder="Qty"></div><div class="col-8"><input class="form-control" type="number" step="0.01" name="unit_price" placeholder="Selling price"></div></div><button class="btn btn-outline-primary w-100 mt-2">Add Part</button></form></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>